  ('elementary-8b44517b-moex-00767', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於夫妻共同收養子女，下列敘述，何者錯誤？', '["夫妻不得收養其直系血親為養子女", "夫妻之一方收養他方之親生子女，無須夫妻共同為之", "夫妻之一方於婚前有收養子女者，婚後，他方必須收養該名養子女", "夫妻之一方不能為意思表示或生死不明已逾3年者，他方得單獨收養子女"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00768', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依民法規定，下列何者無法對受婚生推定之子女提起婚生否認之訴？', '["受婚生推定之夫", "生母", "曾祖父母", "該子女本人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00769', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '甲立遺囑遺贈其所有之房屋一棟於乙。惟該房屋因丙之過失致毀損滅失。一年後，甲死亡。下列敘述， 何者正確？', '["消滅時效已完成，乙不得向丙請求損害賠償", "房屋已毀損滅失，不屬於遺產，遺贈無效", "推定以甲對丙之損害賠償請求權為遺贈", "乙得向甲之繼承人請求債務不履行之損害賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00770', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於偵查中羈押之敘述，何者正確？', '["被告犯罪嫌疑重大，檢察官即可羈押", "被告涉嫌公然侮辱罪，檢察官亦可羈押", "如果被告有反覆實行同一竊盜犯罪之高度可能性，法院可裁定羈押", "即使被告有勾串共犯的可能，法院也不可以裁定羈押"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00771', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於刑法第136條聚眾妨害公務罪構成要件之敘述，何者正確？', '["行為主體限於公務員執行職務之相對人", "行為地限於公共場所或公眾得出入之場所", "聚集人數須達5人以上", "首謀及下手實施強暴脅迫，因而致公務員於死或重傷，與傷害致死或傷害致重傷罪，數罪併罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00772', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於嚴格證明法則之敘述，何者錯誤？', '["嚴格證明與自由證明並不相同", "嚴格證明法則涉及證據能力及有無經合法調查證據之程序", "犯罪事實存在之認定需要嚴格之證明", "自由證明與自由心證之意義相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00773', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '被告以外之人於審判外之書面或言詞陳述，其有無證據能力之判斷，應依何種法則判斷之？', '["自白法則", "傳聞法則", "自由心證法則", "意見法則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00774', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依刑事訟法第27條規定，被告或犯罪嫌疑人得隨時選任辯護人，不包括下列何種情形？', '["受司法警察調查時", "法院審理準備程序", "受上級長官調查時", "移送檢察官調查時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00775', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列關於貪污治罪條例相關法條之敘述，何者錯誤？', '["對於公務員違背職務之行為，要求、期約或收受賄賂或其他不正利益者，構成犯罪", "對於公務員職務上之行為，要求、期約或收受賄賂或其他不正利益者，不構成犯罪", "對於主管或監督之事務，明知違背法令等規定，直接或間接圖自己或其他私人不法利益，因而獲得利 益者，構成犯罪", "對於非主管或監督之事務，明知違背法令等規定，利用職權機會或身分圖自己或其他私人不法利益， 因而獲得利益者，構成犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00776', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '甲犯侵占罪，尚未被發覺，妻子乙為庇護甲而出面向警方表示係其犯罪，乙是否符合刑法自首要件？', '["不符合，因警方並非偵查機關，向警方自首，於法未合", "符合，因犯罪既尚未被發覺，乙出面向警方坦承犯行，當屬自首", "不符合，因乙非侵占罪行為人，乙自無自首問題", "符合，因可以轉換成乙所犯頂替罪之自首"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
